+      latencies.push(latency);
+
+      results.samples.push({
+        id: sample.id,
+        description: sample.description,
+        latency_ms: latency,
+        success: false,
+        confidence: 0,
+        strategy: 'error',
+        error: e.message,
+      });
+
+      process.stdout.write(`\rProgress: ${results.samples.length}/${dataset.length}`);
+    }
