+
+fn create_chunk(code: &str, node_type: &str) -> CodeChunk {
+    CodeChunk {
+        code: code.to_string(),
+        start_byte: 0,
+        end_byte: code.len(),
+        start_line: 0,
+        end_line: code.lines().count().saturating_sub(1),
+        node_type: node_type.to_string(),
+        parent_type: None,
+    }
